args.sparql:
SELECT ?person ?personLabel (YEAR(?appointmentDate) - YEAR(?birthDate) AS ?age)
WHERE {
  ?person p:P39 ?statement .
  ?statement ps:P39 wd:Q5174683 ;
            pq:P580 ?appointmentDate .
  ?person wdt:P569 ?birthDate .
  ?person rdfs:label ?personLabel . FILTER(LANG(?personLabel) = "en")
}
ORDER BY ?age
LIMIT 3
